import{c as t,bj as n,aQ as o,aT as a,l as s}from"./chunks/framework.BSLq2HW8.js";const u=JSON.parse('{"title":"Loop","description":"","frontmatter":{},"headers":[],"relativePath":"documentation/field-types/loop.md","filePath":"documentation/field-types/loop.md","lastUpdated":1772776319000}'),i={name:"documentation/field-types/loop.md"};function l(r,e,p,d,c,h){return n(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="loop" tabindex="-1">Loop <a class="header-anchor" href="#loop" aria-label="Permalink to “Loop”">​</a></h1><p>Loops can execute a <a href="/documentation/segment.html">segment</a> a number of times. Loops are handy, if you want to run the same segment over and over again, each time. You can use <a href="/documentation/variable.html#loop-variable">Loop Variables</a> to access information about the current loop iteration.</p><img src="'+s+`" alt="Loop"><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to “Options”">​</a></h2><table tabindex="0"><thead><tr><th>Options</th><th>Required</th></tr></thead><tbody><tr><td><a href="#which-segment-do-you-want-to-execute"><strong>Which segment do you want to execute</strong></a></td><td><strong>Yes</strong></td></tr><tr><td><a href="#how-many-times-the-segment-has-to-be-run"><strong>How many times the segment has to be run</strong></a></td><td><strong>Yes</strong></td></tr><tr><td><a href="#if-field-value-is-multiline"><strong>If field value is multiline</strong></a></td><td>No</td></tr><tr><td><a href="#character-that-splits-field-value-into-multiline"><strong>Character that splits field value into multiline</strong></a></td><td>No</td></tr><tr><td><a href="#store-loop-index"><strong>Store Loop Index</strong></a></td><td>No</td></tr><tr><td><a href="#delete-store-loop-index-data-before-execution-of-last-index-of-loop"><strong>Delete store loop index data before execution of last index of loop</strong></a></td><td>No</td></tr></tbody></table><h2 id="which-segment-do-you-want-to-execute" tabindex="-1">Which segment do you want to execute <a class="header-anchor" href="#which-segment-do-you-want-to-execute" aria-label="Permalink to “Which segment do you want to execute”">​</a></h2><p>The name of the <a href="/documentation/segment.html">segment</a> which is to be executed in the loop comes in this option.</p><div><p><strong>Using Variables in Segment Name:</strong> You can use <a href="/documentation/variable.html#loop-variable">Loop Variables</a> within the segment name to dynamically execute different segments in each iteration.</p><ul><li>Example: <code>segment-{{loop.index[loop]}}</code></li><li>Segment execution: <code>segment-1</code>, <code>segment-2</code>, <code>segment-3</code>, etc.</li></ul></div><h2 id="how-many-times-the-segment-has-to-be-run" tabindex="-1">How many times the segment has to be run <a class="header-anchor" href="#how-many-times-the-segment-has-to-be-run" aria-label="Permalink to “How many times the segment has to be run”">​</a></h2><p>The number of times the loop has to be executed is given in it. In this, value can be given in the following way.</p><ul><li><strong>Value</strong> - Specify a fixed number or use variables</li><li><strong>Element Length</strong> - Loop based on the number of matching elements on the page</li></ul><h3 id="element-length-option" tabindex="-1">Element Length Option <a class="header-anchor" href="#element-length-option" aria-label="Permalink to “Element Length Option”">​</a></h3><p>The <strong>Element Length</strong> option allows you to run a loop based on the number of elements found on the page that match a specific selector.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT: Use Selector Only, Not Numbers</p><p>In the <strong>Element Length</strong> option, you should <strong>ONLY use an Element Selector Query</strong> (CSS Selector or XPath). <strong>DO NOT use numbers</strong> in this field. The number of loop iterations will be automatically determined by counting how many elements match your selector.</p></div><p><strong>How it works:</strong></p><ol><li>Provide a CSS Selector or XPath query</li><li>The extension counts how many elements match that selector</li><li>The loop runs that many times (once for each matching element)</li></ol><p><strong>Example:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Selector Type: CSS Selector</span></span>
<span class="line"><span>Element Selector Query: table tbody tr</span></span></code></pre></div><p>If there are 10 table rows (<code>&lt;tr&gt;</code>) on the page, the loop will run 10 times.</p><p><strong>Use Cases:</strong></p><ul><li>Process all items in a list</li><li>Fill multiple form sections</li><li>Handle dynamic content where the count varies</li><li>Interact with table rows</li><li>Process search results</li></ul><h3 id="stopping-a-loop-using-loop-index" tabindex="-1">Stopping a Loop Using Loop Index <a class="header-anchor" href="#stopping-a-loop-using-loop-index" aria-label="Permalink to “Stopping a Loop Using Loop Index”">​</a></h3><p>If you want to stop a loop at a specific iteration number (e.g., stop at index 5), use the <strong>String Matching</strong> field type with the <strong>Loop Index</strong> option.</p><p><strong>Steps to Stop Loop at Specific Index:</strong></p><ol><li>Add a <strong><a href="/documentation/field-types/string-matching.html">String Matching</a></strong> field inside your loop segment</li><li>In String Matching field settings: <ul><li><strong>String 1</strong>: Select &quot;Loop Index&quot; from the dropdown</li><li><strong>String 2</strong>: Enter the index number where you want to stop (e.g., <code>5</code>)</li><li><strong>Matching Type</strong>: Select &quot;Equal to&quot; or appropriate comparison</li></ul></li><li>In <strong>Field Success Response Action</strong>: Select <strong>&quot;Stop Loop&quot;</strong></li></ol><p><strong>Example Configuration:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Field Type: String Matching</span></span>
<span class="line"><span>String 1: Loop Index</span></span>
<span class="line"><span>Matching Type: Equal to</span></span>
<span class="line"><span>String 2: 5</span></span>
<span class="line"><span>Field Success Response Action: Stop Loop</span></span></code></pre></div><p><strong>Result:</strong> The loop will stop when it reaches index 5 (the 6th iteration, since loops start at 0).</p><p><strong>Advanced Example - Stop at Different Conditions:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// Stop when loop index is greater than or equal to 10</span></span>
<span class="line"><span>String 1: Loop Index</span></span>
<span class="line"><span>Matching Type: Greater than or equal to</span></span>
<span class="line"><span>String 2: 10</span></span>
<span class="line"><span>Field Success Response Action: Stop Loop</span></span></code></pre></div><h3 id="practical-example-dynamic-table-row-deletion" tabindex="-1">Practical Example: Dynamic Table Row Deletion <a class="header-anchor" href="#practical-example-dynamic-table-row-deletion" aria-label="Permalink to “Practical Example: Dynamic Table Row Deletion”">​</a></h3><p><strong>Scenario:</strong> You need to delete table rows based on input values, but the DOM updates after each deletion, causing the element count to change.</p><p><strong>Problem:</strong> When you delete a row, the remaining rows shift, and element indices change, making it difficult to target the correct rows.</p><p><strong>Solution:</strong> Use Element Length with proper selector strategy.</p><p><strong>Live Example:</strong> <a href="https://formfiller.ctechhindi.in/example/example36.html" target="_blank" rel="noreferrer">Dynamic Table Row Deletion Demo</a></p><p><strong>How to Handle Dynamic DOM Updates:</strong></p><ol><li><strong>Use Element Length</strong> to count current rows</li><li><strong>Always target the first matching element</strong> in your loop (since indices shift after deletion)</li><li><strong>Use conditional logic</strong> to decide which rows to delete</li><li><strong>Let the loop re-count</strong> elements on each iteration</li></ol><p><strong>Example Configuration:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Loop Field:</span></span>
<span class="line"><span>  - How many times: Element Length</span></span>
<span class="line"><span>  - Selector Type: CSS Selector</span></span>
<span class="line"><span>  - Element Selector Query: table tbody tr</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Inside Loop Segment:</span></span>
<span class="line"><span>  1. Scraping Data Field (Get row data)</span></span>
<span class="line"><span>     - Selector: table tbody tr:first-child .name</span></span>
<span class="line"><span>     - Which Element Option: Element Text</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>  2. String Matching Field (Check if should delete)</span></span>
<span class="line"><span>     - String 1: {$scrapedName$}</span></span>
<span class="line"><span>     - Matching Type: Equal to</span></span>
<span class="line"><span>     - String 2: John Doe</span></span>
<span class="line"><span>     - Field Success Response Action: Continue</span></span>
<span class="line"><span>     - Field Error Response Action: Skip Segment</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>  3. Button Click Field (Delete the row)</span></span>
<span class="line"><span>     - Selector: table tbody tr:first-child .delete-btn</span></span></code></pre></div><p><strong>Key Points:</strong></p><ul><li>Always use <code>:first-child</code> or similar selectors to target the first element</li><li>The DOM updates after deletion, so the next iteration will see the new first element</li><li>Use String Matching to conditionally process rows</li><li>Element Length automatically adjusts as rows are deleted</li></ul><h3 id="loop-starting-and-ending-point" tabindex="-1">Loop Starting and Ending Point <a class="header-anchor" href="#loop-starting-and-ending-point" aria-label="Permalink to “Loop Starting and Ending Point”">​</a></h3><ul><li>From which number the loop has to be started? <code>(Default Index: 0)</code></li><li>What number should the loop end at?</li></ul><div class="warning custom-block"><p class="custom-block-title">NOTE</p><p>Starting number of the loop is <code>0</code>. If you give 4 numbers in the starting number then the loop will start from number 5 because the loop will start from 0. Like - <code>0,1,2,3,4,5,...</code></p></div><details class="details custom-block"><summary>How to run infinite loop?</summary><p>To execute Infinite Loop, give <code>-1</code> in Loop Ending Value.</p></details><details class="details custom-block"><summary>How to stop a loop when using an infinite loop?</summary><p>To stop the loop, you can do it through the field settings given below.</p><ul><li><a href="/documentation/form-fields/field-settings.html#field-success-response-action">Field Success Response Action</a></li><li><a href="/documentation/form-fields/field-settings.html#field-error-response-action">Field Error Response Action</a></li></ul></details><details class="details custom-block"><summary>How to skip any loop index?</summary><p>To skip any loop index (1,2,3,..), use the <code>Field Success Response</code> or <code>Field Error Response</code> options in the field settings. Choice <code>Skip Segment</code> action.</p></details><h2 id="if-field-value-is-multiline" tabindex="-1">If field value is multiline <a class="header-anchor" href="#if-field-value-is-multiline" aria-label="Permalink to “If field value is multiline”">​</a></h2><p>This option allows you to handle multiline field values. When enabled, the loop will process each line of a multiline field value separately.</p><h3 id="character-that-splits-field-value-into-multiline" tabindex="-1">Character that splits field value into multiline <a class="header-anchor" href="#character-that-splits-field-value-into-multiline" aria-label="Permalink to “Character that splits field value into multiline”">​</a></h3><p>This option specifies the character that will be used to split field values into multiple lines. By default, this is set to an string <code>,,</code>, which typically means newline characters are used for splitting.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>If there are values in new line then use <code>\\r\\n</code> for split values.</p></div><h2 id="store-loop-index" tabindex="-1">Store Loop Index <a class="header-anchor" href="#store-loop-index" aria-label="Permalink to “Store Loop Index”">​</a></h2><p>If the page on which you are using the loop is <strong>refreshed</strong> after the loop&#39;s action and the Loop starts from again the first number then you can use this option.</p><div class="info custom-block"><p class="custom-block-title">Remove Store Loop Index Data</p><p>You can remove stored loop index data using the &quot;Remove Store Loop Index Data&quot; button. This clears any previously stored index information.</p></div><h2 id="delete-store-loop-index-data-before-execution-of-last-index-of-loop" tabindex="-1">Delete store loop index data before execution of last index of loop <a class="header-anchor" href="#delete-store-loop-index-data-before-execution-of-last-index-of-loop" aria-label="Permalink to “Delete store loop index data before execution of last index of loop”">​</a></h2><p>This option allows you to automatically delete the stored loop index data before executing the last index of the loop. When enabled, the stored index data will be cleared just before the final iteration runs.</p><h2 id="form-field-has-multiple-elements" tabindex="-1">Form Field has multiple elements <a class="header-anchor" href="#form-field-has-multiple-elements" aria-label="Permalink to “Form Field has multiple elements”">​</a></h2><p>If the field is being used in <code>Loop</code> Field Type, then after turning on this <a href="/documentation/form-fields/field-settings.html#if-this-field-is-being-used-in-a-loop-and-the-field-has-multiple-elements"><code>field setting</code></a>, if the element given in the field is multiple in the page, then we will get one element through the <code>index</code> of the loop.</p>`,59)])])}const m=t(i,[["render",l]]);export{u as __pageData,m as default};
